1	"""Playwright helper — runs in a separate process to avoid asyncio conflicts.
2	
3	Usage: python scripts/pw_render_helper.py <port> <report_file> <output_dir>
4	
5	Reads markdown from report_file, renders it via the live server on the given port,
6	captures a full-page screenshot, and prints DOM stats as JSON to stdout.
7	"""
8	
9	import json
10	import sys
11	from pathlib import Path
12	
13	from playwright.sync_api import sync_playwright
14	
15	INJECT_JS = r"""(reportMd) => {
16	    // Hide existing UI
17	    Array.from(document.body.children).forEach(function(el) { el.style.display = 'none'; });
18	
19	    // Create report container
20	    var wrapper = document.createElement('div');
21	    wrapper.style.cssText = 'width:100%;max-width:900px;margin:0 auto;padding:40px;';
22	    var container = document.createElement('div');
23	    container.className = 'report-rendered';
24	    container.style.cssText = 'display:block;width:100%;';
25	    wrapper.appendChild(container);
26	    document.body.appendChild(wrapper);
27	    document.body.style.overflow = 'visible';
28	    document.body.style.height = 'auto';
29	    document.documentElement.style.overflow = 'visible';
30	
31	    // Render markdown
32	    var html = typeof marked !== 'undefined' ? marked.parse(reportMd) : reportMd;
33	    if (typeof DOMPurify !== 'undefined') {
34	        html = DOMPurify.sanitize(html, {
35	            ADD_ATTR: ['target'],
36	            ADD_DATA_URI_TAGS: ['img'],
37	            ADD_URI_SAFE_ATTR: ['src']
38	        });
39	    }
40	    container.innerHTML = html;
41	
42	    // Apply Key Findings wrapping
43	    html = container.innerHTML;
44	    html = html.replace(
45	        /<p><strong>Key Findings:?<\/strong><\/p>\s*<ul>([\s\S]*?)<\/ul>/gi,
46	        function(m, list) {
47	            return '<div class="key-findings"><div class="key-findings-title">Key Findings</div><ul>' + list + '</ul></div>';
48	        }
49	    );
50	    // Apply :::metrics parsing
51	    html = html.replace(
52	        /<p>:::metrics\s*\n?([\s\S]*?):::<\/p>/gi,
53	        function(m, content) {
54	            var items = content.split('|').map(function(s) { return s.trim(); }).filter(Boolean);
55	            var card = '<div class="report-metrics-card">';
56	            items.forEach(function(item) {
57	                var parts = item.split(':').map(function(s) { return s.trim(); });
58	                if (parts.length >= 2) {
59	                    card += '<div class="metric-item"><div class="metric-value">' + parts[1] + '</div><div class="metric-label">' + parts[0] + '</div></div>';
60	                }
61	            });
62	            card += '</div>';
63	            return card;
64	        }
65	    );
66	    container.innerHTML = html;
67	
68	    return {
69	        containerHeight: container.scrollHeight,
70	        h1: container.querySelectorAll('h1').length,
71	        h2: container.querySelectorAll('h2').length,
72	        h3: container.querySelectorAll('h3').length,
73	        tables: container.querySelectorAll('table').length,
74	        imgs: container.querySelectorAll('img').length,
75	        b64imgs: container.querySelectorAll('img[src*="base64"]').length,
76	        links: container.querySelectorAll('a').length,
77	        lists: container.querySelectorAll('ul,ol').length,
78	        paragraphs: container.querySelectorAll('p').length,
79	        keyFindings: container.querySelectorAll('.key-findings').length,
80	        metricsCards: container.querySelectorAll('.report-metrics-card').length,
81	        wordCount: container.innerText.split(/\s+/).length,
82	        htmlLength: container.innerHTML.length,
83	    };
84	}"""
85	
86	
87	def main():
88	    port = int(sys.argv[1])
89	    report_file = Path(sys.argv[2])
90	    output_dir = Path(sys.argv[3])
91	    output_dir.mkdir(parents=True, exist_ok=True)
92	
93	    report_md = report_file.read_text(encoding="utf-8")
94	
95	    with sync_playwright() as pw:
96	        browser = pw.chromium.launch(headless=True)
97	        page = browser.new_context(
98	            viewport={"width": 1200, "height": 3000}
99	        ).new_page()
100	        page.goto(f"http://localhost:{port}/", timeout=15000)
101	        page.wait_for_load_state("domcontentloaded")
102	
103	        result = page.evaluate(INJECT_JS, report_md)
104	        page.wait_for_timeout(2000)
105	
106	        page.screenshot(
107	            path=str(output_dir / "real_output_full.png"),
108	            full_page=True,
109	        )
110	
111	        # Viewport shots
112	        page.set_viewport_size({"width": 1200, "height": 900})
113	        page.evaluate("() => window.scrollTo(0, 0)")
114	        page.wait_for_timeout(300)
115	        page.screenshot(
116	            path=str(output_dir / "real_output_top.png"),
117	            full_page=False,
118	        )
119	
120	        browser.close()
121	
122	    print(json.dumps(result))
123	
124	
125	if __name__ == "__main__":
126	    main()
